tool.command:
exec 3>&1 4>&2; exec > enzywizard.log 2>&1;
MSMS_EXE=\$(command -v msms || command -v msms.x86_64Linux2.2.6.1 || true); if [ -n "\$MSMS_EXE" ]; then mkdir -p "\$HOME"; echo "set pyvol_msms_exe, \$MSMS_EXE" > "\$HOME/.pymolrc"; fi;
#set $input_name = $input_path.element_identifier ln -s '$input_path' '$input_name' && mkdir -p substrate_dir_raw substrate_dir && unzip -q '$substrate_zip' -d substrate_dir_raw && find substrate_dir_raw -type f \( -iname '*.sdf' \) -exec cp -L {} substrate_dir/ \; && enzywizard-dock -i '$input_name' -s '$substrate_names' -d substrate_dir -o ./ --max_docking_attempt_num '$advanced.max_docking_attempt_num' $advanced.no_early_stop --exhaustiveness '$advanced.exhaustiveness' --cpu "\${GALAXY_SLOTS:-1}" --min_rad '$advanced.min_rad' --max_rad '$advanced.max_rad' --min_volume '$advanced.min_volume' #if $advanced.catalytic_residue: --catalytic_residue '$advanced.catalytic_residue' #end if #if $advanced.catalytic_site_coord: --catalytic_site_coord '$advanced.catalytic_site_coord' #end if #if $advanced.box_size: --box_size '$advanced.box_size' #end if ; status=\$?; echo "---- files in Galaxy job working directory ----" >&4; find . -maxdepth 4 -type f | sort >&4; if [ "\$status" -ne 0 ]; then cat enzywizard.log >&4; exit "\$status"; fi; if ! find . -maxdepth 2 -type f \( -name 'dock_report*.json' -o -name 'docked*.cif' -o -name 'docked*.pdb' -o -name 'docked*.sdf' \) | grep -q .; then echo "No EnzyWizard Dock output files were produced." >&4; cat enzywizard.log >&4; [ -f log.txt ] && cat log.txt >&4; exit 1; fi;
